variables {
  environment = "test"
  cidr_block  = "10.99.0.0/16"
}

mock_provider "aws" {
  mock_data "aws_availability_zones" {
    defaults = {
      names = ["us-east-1a", "us-east-1b"]
    }
  }
}

run "validate_vpc_plan" {
  command = plan

  assert {
    condition     = output.vpc_cidr == "10.99.0.0/16"
    error_message = "VPC CIDR should match the test variable"
  }

  assert {
    condition     = length(output.subnet_ids) == 2
    error_message = "Should create one subnet per availability zone (2 total)"
  }
}
